"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";

export default function JobActions({ instanceId }: { instanceId: string }) {
  const router = useRouter();
  const [busy, setBusy] = useState<string | null>(null);
  const [cmd, setCmd] = useState("");
  const [pkgs, setPkgs] = useState("");

  const dispatch = async (
    type: string,
    payload: Record<string, unknown> = {},
    label = type
  ) => {
    setBusy(label);
    try {
      const r = await fetch("/api/admin/jobs", {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          instance_ids: [instanceId],
          type,
          payload,
        }),
      });
      if (!r.ok) alert(`Failed: ${r.status}`);
      else router.refresh();
    } finally {
      setBusy(null);
    }
  };

  return (
    <div className="row">
      <button
        className="secondary"
        disabled={!!busy}
        onClick={() => dispatch("check_updates")}
      >
        {busy === "check_updates" ? "…" : "Check updates"}
      </button>
      <button
        disabled={!!busy}
        onClick={() => dispatch("install_updates")}
      >
        {busy === "install_updates" ? "…" : "Install all updates"}
      </button>
      <button
        disabled={!!busy}
        onClick={() =>
          dispatch("install_updates", { security_only: true }, "install_updates_sec")
        }
      >
        {busy === "install_updates_sec" ? "…" : "Security updates only"}
      </button>
      <button
        className="secondary"
        disabled={!!busy}
        onClick={() => {
          if (confirm("Schedule reboot on this host?")) dispatch("reboot");
        }}
      >
        Reboot
      </button>
      <div style={{ width: "100%", height: 1 }} />
      <input
        placeholder="package names (space-separated)"
        value={pkgs}
        onChange={(e) => setPkgs(e.target.value)}
        style={{ flex: 1, minWidth: 240 }}
      />
      <button
        className="secondary"
        disabled={!!busy || !pkgs.trim()}
        onClick={() =>
          dispatch(
            "install_package",
            { packages: pkgs.split(/[\s,]+/).filter(Boolean) },
            "install_package"
          ).then(() => setPkgs(""))
        }
      >
        Install packages
      </button>
      <div style={{ width: "100%", height: 1 }} />
      <input
        placeholder="shell command"
        value={cmd}
        onChange={(e) => setCmd(e.target.value)}
        style={{ flex: 1, minWidth: 240, fontFamily: "ui-monospace, monospace" }}
      />
      <button
        className="secondary"
        disabled={!!busy || !cmd.trim()}
        onClick={() =>
          dispatch("run_command", { command: cmd }, "run_command").then(() =>
            setCmd("")
          )
        }
      >
        Run
      </button>
    </div>
  );
}
